import { useState, useCallback, useImperativeHandle, forwardRef } from "react";
import { useDropzone } from "react-dropzone";
import { Card, CardContent } from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import { CloudUpload, X, Zap } from "lucide-react";
import { AnimatePresence } from "framer-motion";
import ValidationCard from "./validation-card";
import { LazyLoading } from "./ui/lazy-loading";
import { validateImageForInstallation, validateImageForFaultDetection, ValidationResult } from "@/lib/image-validation";

interface ImageUploadProps {
  onUpload: (file: File) => void;
  onAnalyze?: (file: File) => void;
  uploading?: boolean;
  accept?: string;
  maxSize?: number;
  title: string;
  description: string;
  validationType: "installation" | "fault-detection";
}

export interface ImageUploadRef {
  reset: () => void;
}

const ImageUpload = forwardRef<ImageUploadRef, ImageUploadProps>(({
  onUpload,
  onAnalyze,
  uploading = false,
  accept = "image/*",
  maxSize = 8 * 1024 * 1024, // 8MB (reduced for better performance)
  title,
  description,
  validationType
}: ImageUploadProps, ref) => {
  const [uploadedFile, setUploadedFile] = useState<File | null>(null);
  const [preview, setPreview] = useState<string | null>(null);
  const [validationResult, setValidationResult] = useState<ValidationResult | null>(null);
  const [isValidating, setIsValidating] = useState(false);
  const [showValidationCard, setShowValidationCard] = useState(false);
  const [showThinkingAnimation, setShowThinkingAnimation] = useState(false);

  // Expose reset method to parent components
  useImperativeHandle(ref, () => ({
    reset: () => {
      setUploadedFile(null);
      if (preview) {
        URL.revokeObjectURL(preview);
      }
      setPreview(null);
      setValidationResult(null);
      setIsValidating(false);
      setShowValidationCard(false);
      setShowThinkingAnimation(false);
    }
  }));

  const onDrop = useCallback(async (acceptedFiles: File[]) => {
    const file = acceptedFiles[0];
    if (file) {
      // Show preview immediately with thinking animation
      setUploadedFile(file);
      setPreview(URL.createObjectURL(file));
      setShowThinkingAnimation(true);

      setIsValidating(true);
      setValidationResult({
        isValid: false,
        type: "validating",
        title: "Validating Image",
        description: "Please wait while we validate your image..."
      });

      try {
        const result = validationType === "installation" 
          ? await validateImageForInstallation(file)
          : await validateImageForFaultDetection(file);

        setValidationResult(result);
        setShowValidationCard(true);

        if (result.isValid) {
          onUpload(file);
        } else {
          // If validation fails, remove the preview
          setUploadedFile(null);
          if (preview) {
            URL.revokeObjectURL(preview);
          }
          setPreview(null);
        }

        // Auto-hide validation card after 4 seconds to give user time to read
        setTimeout(() => {
          setShowValidationCard(false);
        }, 4000);
      } catch (error) {
        console.error('Validation error:', error);
        setValidationResult({
          isValid: false,
          type: "error",
          title: "Validation Failed",
          description: "Unable to validate the image. Please try again."
        });
        setShowValidationCard(true);

        // Auto-hide validation card after 4 seconds to give user time to read
        setTimeout(() => {
          setShowValidationCard(false);
        }, 4000);
      } finally {
        setIsValidating(false);
        setShowThinkingAnimation(false);
      }
    }
  }, [onUpload, validationType, preview]);

  const { getRootProps, getInputProps, isDragActive } = useDropzone({
    onDrop,
    accept: { [accept]: [] },
    maxSize,
    multiple: false,
    disabled: uploading
  });

  const removeFile = () => {
    setUploadedFile(null);
    setValidationResult(null);
    if (preview) {
      URL.revokeObjectURL(preview);
      setPreview(null);
    }
  };

  return (
    <>
      {/* Validation Card - Responsive positioning below navbar */}
      <AnimatePresence>
        {showValidationCard && validationResult && (
          <div className="fixed top-20 sm:top-24 md:top-28 right-2 sm:right-4 md:right-6 z-[10000] w-full max-w-xs sm:max-w-sm md:max-w-md px-2 sm:px-0">
            <ValidationCard
              type={validationResult.type}
              title={validationResult.title}
              description={validationResult.description}
              onClose={() => setShowValidationCard(false)}
            />
          </div>
        )}
      </AnimatePresence>

      <Card className="shadow-material">
        <CardContent className="p-4 sm:p-6 md:p-8">
          <h3 className="text-lg sm:text-xl md:text-2xl font-bold mb-4 sm:mb-6 text-primary-custom">{title}</h3>

        {!uploadedFile ? (
          <div
            {...getRootProps()}
            className={`border-2 border-dashed rounded-lg p-6 sm:p-8 md:p-10 text-center transition-colors cursor-pointer ${
              isDragActive
                ? 'border-primary bg-blue-50'
                : 'border-gray-300 hover:border-primary'
            } ${uploading ? 'opacity-50 cursor-not-allowed' : ''}`}
          >
            <input {...getInputProps()} />
            <CloudUpload className="mx-auto text-gray-400 mb-3 sm:mb-4" size={32} />
            <p className="text-sm sm:text-base text-secondary-custom mb-2">
              {isDragActive ? 'Drop the image here' : 'Drag and drop your image here'}
            </p>
            <p className="text-xs sm:text-sm text-secondary-custom mb-3 sm:mb-4">or click to browse files</p>
            <p className="text-xs sm:text-sm text-secondary-custom mb-2">
              Supported formats: JPG, PNG, TIFF (Max 20MB)
            </p>
            <p className="text-xs sm:text-sm text-orange-600 dark:text-orange-400 mb-3 sm:mb-4 px-2">
              {title.includes('Installation') || title.includes('Rooftop')
                ? 'Upload rooftop or building images only (aerial/angled views)'
                : 'Upload solar panel or photovoltaic equipment images only'
              }
            </p>
            <Button 
              type="button" 
              className="bg-primary hover:bg-blue-700 text-white text-sm sm:text-base h-10 sm:h-11 px-4 sm:px-6"
              disabled={uploading}
            >
              {uploading ? 'Uploading...' : 'Select Image'}
            </Button>
          </div>
        ) : (
          <div className="space-y-4">
            <div className="relative">
              <img
                src={preview || ''}
                alt="Upload preview"
                className={`w-full h-48 sm:h-56 md:h-64 object-contain rounded-lg border border-gray-200 bg-gray-50 transition-all duration-300 ${
                  showThinkingAnimation ? 'opacity-70' : 'opacity-100'
                }`}
              />

              {/* Thinking Animation Overlay */}
              {showThinkingAnimation && (
                <div className="absolute inset-0 flex items-center justify-center bg-black bg-opacity-20 rounded-lg">
                  <div className="bg-white bg-opacity-90 rounded-lg p-4 flex items-center space-x-3 shadow-lg">
                    <div className="flex space-x-1">
                      <div className="w-2 h-2 bg-blue-500 rounded-full animate-bounce"></div>
                      <div className="w-2 h-2 bg-blue-500 rounded-full animate-bounce" style={{ animationDelay: '0.1s' }}></div>
                      <div className="w-2 h-2 bg-blue-500 rounded-full animate-bounce" style={{ animationDelay: '0.2s' }}></div>
                    </div>
                    <span className="text-sm text-gray-700 font-medium">Thinking...</span>
                  </div>
                </div>
              )}

              <button
                onClick={removeFile}
                className="absolute top-2 right-2 bg-red-500 text-white rounded-full p-1.5 hover:bg-red-600 transition-colors"
              >
                <X size={16} />
              </button>
            </div>
            <div className="text-sm text-secondary-custom space-y-1">
              <p><strong>File:</strong> {uploadedFile.name}</p>
              <p><strong>Size:</strong> {(uploadedFile.size / 1024 / 1024).toFixed(2)} MB</p>
            </div>
            {onAnalyze && (
              <Button 
                onClick={() => onAnalyze(uploadedFile)}
                disabled={uploading || isValidating || !validationResult?.isValid}
                className="w-full bg-primary hover:bg-blue-700 text-white h-11 sm:h-12 text-sm sm:text-base disabled:opacity-50 disabled:cursor-not-allowed"
              >
                {uploading ? (
                  <>
                    <div className="animate-spin rounded-full h-4 w-4 border-b-2 border-white mr-2"></div>
                    Analyzing...
                  </>
                ) : isValidating ? (
                  <>
                    <div className="animate-spin rounded-full h-4 w-4 border-b-2 border-white mr-2"></div>
                    Validating...
                  </>
                ) : !validationResult?.isValid ? (
                  <>
                    <X className="mr-2" size={16} />
                    Image Validation Required
                  </>
                ) : (
                  <>
                    <Zap className="mr-2" size={16} />
                    Start AI Analysis
                  </>
                )}
              </Button>
            )}
          </div>
        )}

        <p className="text-xs sm:text-sm text-secondary-custom mt-4 px-2">{description}</p>
      </CardContent>
    </Card>
    </>
  );
});

ImageUpload.displayName = 'ImageUpload';

export default ImageUpload;

client/src/components/installation-analy.content:
import { useState, useRef, useEffect } from "react";
import { useMutation } from "@tanstack/react-query";
import { motion, AnimatePresence } from "framer-motion";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import { Badge } from "@/components/ui/badge";
import { Label } from "@/components/ui/label";
import { Input } from "@/components/ui/input";
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from "@/components/ui/select";
import { CheckCircle, Download, Share, Settings, FileText, Home, Ruler, ChevronDown, ChevronUp, FileDown, X } from "lucide-react";

import ImageUpload, { ImageUploadRef } from "./image-upload";
import AnalysisOverlay from "./analysis-overlay";
import { LazyLoading, LazyLoadingOverlay } from "./ui/lazy-loading";
import { apiRequest, checkBackendHealth } from "@/lib/queryClient";
import { useToast } from "@/hooks/use-toast";
import { generateInstallationPDF } from "@/lib/pdf-generator";
import { compressImage, safeStoreImage, cleanupOldImages } from "@/lib/image-utils";
import { measureTime } from "@/lib/performance-monitor";

import type { InstallationResult, RoofInput } from "@shared/schema";

export default function InstallationAnalysis() {
  const [analysisResult, setAnalysisResult] = useState<InstallationResult | null>(null);
  const [imageUrl, setImageUrl] = useState<string | null>(null);
  const [roofInput, setRoofInput] = useState<RoofInput>({
    roofSize: undefined,
    roofShape: 'auto-detect',
    panelSize: 'auto-optimize'
  });
  const [isRoofDetailsOpen, setIsRoofDetailsOpen] = useState(false);
  const { toast } = useToast();
  const resultsRef = useRef<HTMLDivElement>(null);
  const analysisCanvasRef = useRef<HTMLCanvasElement>(null);
  const imageUploadRef = useRef<ImageUploadRef | null>(null);

  // Load data from sessionStorage on component mount (persists during navigation, clears on refresh)
  useEffect(() => {
    // Clean up old images first to free space
    cleanupOldImages();

    const savedResult = sessionStorage.getItem('installationAnalysisResult');
    const savedRoofInput = sessionStorage.getItem('installationRoofInput');

    if (savedResult) {
      try {
        const parsedResult = JSON.parse(savedResult);
        setAnalysisResult(parsedResult);

        // If result has embedded image URL, use it
        if (parsedResult.originalImageUrl) {
          setImageUrl(parsedResult.originalImageUrl);
        }
      } catch (error) {
        console.error('Error parsing saved installation result:', error);
      }
    }

    if (savedRoofInput) {
      try {
        const parsedRoofInput = JSON.parse(savedRoofInput);
        setRoofInput(parsedRoofInput);
      } catch (error) {
        console.error('Error parsing saved roof input:', error);
      }
    }
  }, []);

  // Save data to sessionStorage whenever it changes with safe storage
  useEffect(() => {
    if (analysisResult) {
      try {
        const dataString = JSON.stringify(analysisResult);
        sessionStorage.setItem('installationAnalysisResult', dataString);
      } catch (error) {
        console.error('Error saving analysis result to storage:', error);
        // If storage fails, clean up and try again
        cleanupOldImages();
        try {
          sessionStorage.setItem('installationAnalysisResult', JSON.stringify(analysisResult));
        } catch (retryError) {
          console.warn('Failed to save analysis result even after cleanup:', retryError);
        }
      }
    }
  }, [analysisResult]);

  useEffect(() => {
    sessionStorage.setItem('installationRoofInput', JSON.stringify(roofInput));
  }, [roofInput]);

  const uploadMutation = useMutation({
    mutationFn: async (file: File) => {
      const formData = new FormData();
      formData.append('image', file);
      formData.append('userId', '1'); // Default user ID

      const response = await apiRequest('POST', '/api/analyze/installation', formData);
      return response.json();
    },
    onSuccess: (data) => {
      // Store the uploaded file path for AI analysis
      setAnalysisResult(null); // Reset previous results
      toast({
        title: "Image Uploaded",
        description: "Click 'Start AI Analysis' to analyze your rooftop image.",
        variant: "success",
      });
    },
    onError: (error) => {
      toast({
        title: "Upload Failed",
        description: "Failed to upload the image. Please try again.",
        variant: "destructive",
      });
    },
  });

  const analysisMutation = useMutation({
    mutationFn: async (file: File) => {
      console.log('Starting analysis for file:', file.name, file.size);

      const formData = new FormData();
      formData.append('image', file);
      formData.append('userId', '1');

      // Add roof input data
      if (roofInput.roofSize) {
        formData.append('roofSize', roofInput.roofSize.toString());
      }
      if (roofInput.roofShape) {
        formData.append('roofShape', roofInput.roofShape);
      }
      if (roofInput.panelSize) {
        formData.append('panelSize', roofInput.panelSize);
      }

      console.log('FormData created with roof inputs, sending request...');

      const response = await apiRequest('POST', '/api/analyze/installation', formData);
      const data = await response.json();
      console.log('Analysis successful:', data);
      return data;
    },
    onSuccess: async (data, variables) => {
      console.log('Analysis complete, setting results:', data);

      try {
        // Compress image for storage efficiency
        const compressedDataUrl = await compressImage(variables, 1200, 0.8);

        // Create enhanced result with compressed image data
        const enhancedResult = {
          ...data.results,
          originalImageUrl: compressedDataUrl,
          timestamp: new Date().toISOString()
        };

        setAnalysisResult(enhancedResult);
        setImageUrl(compressedDataUrl);
      } catch (error) {
        console.error('Error compressing result image:', error);
        // Fallback to standard file reading
        const reader = new FileReader();
        reader.onload = (e) => {
          const dataUrl = e.target?.result as string;
          const enhancedResult = {
            ...data.results,
            originalImageUrl: dataUrl,
            timestamp: new Date().toISOString()
          };
          setAnalysisResult(enhancedResult);
          setImageUrl(dataUrl);
        };
        reader.readAsDataURL(variables);
      }

      // Reset the image uploader to refresh the UI
      if (imageUploadRef.current) {
        imageUploadRef.current.reset();
      }

      // Smooth scroll to results after a brief delay, accounting for navbar height
      setTimeout(() => {
        if (resultsRef.current) {
          const navbarHeight = 80; // Account for navbar height (pt-20 = 80px)
          const elementTop = resultsRef.current.offsetTop - navbarHeight;
          window.scrollTo({
            top: elementTop,
            behavior: 'smooth'
          });
        }
      }, 300);

      toast({
        title: "Analysis Complete",
        description: "Your rooftop analysis has been completed successfully.",
        variant: "success",
      });
    },
    onError: (error) => {
      console.error('Analysis error:', error);

      // Extract error message and provide specific validation warnings
      let errorMessage = "Failed to analyze the image. Please try again.";
      let errorTitle = "Analysis Failed";

      if (error instanceof Error) {
        const errorText = error.message.toLowerCase();

        if (errorText.includes('not a rooftop') || errorText.includes('no roof') || errorText.includes('solar panel')) {
          errorTitle = "Invalid Image for Installation Analysis";
          errorMessage = "Please upload a rooftop or building image. This feature analyzes roof structures for solar panel installation planning, not existing solar panels.";
        } else if (errorText.includes('indoor') || errorText.includes('interior')) {
          errorTitle = "Indoor Image Detected";
          errorMessage = "Please upload an outdoor rooftop image. Indoor or interior photos cannot be used for solar installation planning.";
        } else if (errorText.includes('invalid') || errorText.includes('not valid')) {
          errorTitle = "Image Validation Failed";
          errorMessage = "Please upload a clear rooftop image showing the building structure from an aerial or angled view.";
        } else if (errorText.includes('overloaded') || errorText.includes('503') || errorText.includes('unavailable')) {
          errorTitle = "AI Service Temporarily Unavailable";
          errorMessage = "The AI analysis service is currently overloaded. Please wait a few minutes and try again. If the issue persists, try a different image or contact support.";

          // Use warning variant for service unavailability
          toast({
            title: errorTitle,
            description: errorMessage,
            variant: "warning",
          });
          return;
        } else if (errorText.includes('network') || errorText.includes('timeout')) {
          errorTitle = "Connection Error";
          errorMessage = "Network connection failed. Please check your internet connection and try again.";
        } else if (errorText.includes('backend not connected') || errorText.includes('server not available')) {
          errorTitle = "Backend Connection Error";
          errorMessage = "The backend server is not connected properly. Please check the server status and try again.";
        } else if (errorText.includes('fetch') || errorText.includes('cors') || errorText.includes('refused')) {
          errorTitle = "Backend Connection Error";
          errorMessage = "Cannot connect to the backend server. Please ensure the server is running and try again.";
        } else {
          errorMessage = error.message;
        }
      }

      // Always show the toast notification
      toast({
        title: errorTitle,
        description: errorMessage,
        variant: "destructive",
      });
    },
  });

  const handleImageUpload = async (file: File) => {
    try {
      // Compress image for better performance and storage efficiency
      const compressedDataUrl = await compressImage(file, 1200, 0.8);
      setImageUrl(compressedDataUrl);
    } catch (error) {
      console.error('Error compressing image:', error);
      // Fallback to original file reading
      const reader = new FileReader();
      reader.onload = (e) => {
        const dataUrl = e.target?.result as string;
        setImageUrl(dataUrl);
      };
      reader.readAsDataURL(file);
    }
  };

  const handleAnalyze = async (file: File) => {
    const endTimer = measureTime('InstallationAnalysis', 'handleAnalyze');

    try {
      // Check backend health before analysis
      const isHealthy = await checkBackendHealth();
      if (!isHealthy) {
        toast({
          title: "Backend Connection Error",
          description: "Cannot connect to the backend server. Please ensure the server is running and try again.",
          variant: "warning",
        });
        endTimer(false, 'Backend health check failed');
        return;
      }

      analysisMutation.mutate(file);
      endTimer(true);
    } catch (error) {
      endTimer(false, error instanceof Error ? error.message : 'Unknown error');
    }
  };

  const exportCompletePDF = async () => {
    if (!analysisResult || !imageUrl) return;

    try {
      await generateInstallationPDF(analysisResult, imageUrl, analysisCanvasRef);
      toast({
        title: "Complete Report Generated",
        description: "Comprehensive installation analysis report has been downloaded as a PDF.",
        variant: "success",
      });
    } catch (error) {
      console.error('PDF generation error:', error);
      toast({
        title: "Export Failed",
        description: "Failed to generate complete PDF report. Please try again.",
        variant: "destructive",
      });
    }
  };

  const exportQuickSummaryPDF = async () => {
    if (!analysisResult || !imageUrl) return;

    try {
      // Create a simplified version of the analysis result for quick summary
      const summaryResult = {
        ...analysisResult,
        notes: analysisResult.notes?.split('\n').slice(0, 3).join('\n') || '', // First 3 lines only
        recommendations: analysisResult.recommendations?.slice(0, 3) || [], // First 3 recommendations only
      };

      await generateInstallationPDF(summaryResult, imageUrl, analysisCanvasRef);
      toast({
        title: "Quick Summary Generated",
        description: "Executive summary report has been downloaded as a PDF.",
        variant: "success",
      });
    } catch (error) {
      console.error('PDF generation error:', error);
      toast({
        title: "Export Failed",
        description: "Failed to generate quick summary PDF. Please try again.",
        variant: "destructive",
      });
    }
  };

  const exportToJson = () => {
    if (!analysisResult) return;

    const exportData = {
      analysisDate: new Date().toISOString(),
      type: 'installation',
      results: analysisResult,
      metadata: {
        generatedBy: 'SolarScope AI',
        version: '1.0',
        confidence: '94%'
      }
    };

    const blob = new Blob([JSON.stringify(exportData, null, 2)], { type: 'application/json' });
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    a.download = `solar-installation-data-${new Date().toISOString().split('T')[0]}.json`;
    document.body.appendChild(a);
    a.click();
    document.body.removeChild(a);
    URL.revokeObjectURL(url);

    toast({
      title: "Data Exported",
      description: "Installation analysis data has been downloaded as a JSON file.",
    });
  };

  const clearAnalysisData = () => {
    // Clean up object URL to prevent memory leaks
    if (imageUrl) {
      URL.revokeObjectURL(imageUrl);
    }

    // Clear all analysis data
    setAnalysisResult(null);
    setImageUrl(null);
    setRoofInput({
      roofSize: undefined,
      roofShape: 'auto-detect',
      panelSize: 'auto-optimize'
    });
    setIsRoofDetailsOpen(false);

    // Clear session storage
    sessionStorage.removeItem('installationAnalysisResult');
    sessionStorage.removeItem('installationImageUrl');
    sessionStorage.removeItem('installationRoofInput');

    toast({
      title: "Analysis Cleared",
      description: "Installation analysis data has been cleared.",
      variant: "success",
    });
  };

  return (
    <div className="space-y-4 sm:space-y-6 px-2 sm:px-0">
      {/* Roof Input Form */}
      <Card className="shadow-material">
        <CardHeader 
          className="pb-3 sm:pb-4 px-3 sm:px-6 py-3 sm:py-6 cursor-pointer hover:bg-gray-50 transition-colors"
          onClick={() => setIsRoofDetailsOpen(!isRoofDetailsOpen)}
        >
          <CardTitle className="flex items-center justify-between text-base sm:text-lg md:text-xl">
            <div className="flex items-center gap-2">
              <Home className="w-4 h-4 sm:w-5 sm:h-5 text-primary" />
              <span className="truncate">Roof Details (Optional)</span>
            </div>
            <motion.div
              animate={{ rotate: isRoofDetailsOpen ? 180 : 0 }}
              transition={{ duration: 0.3, ease: "easeInOut" }}
            >
              <ChevronDown className="w-4 h-4 sm:w-5 sm:h-5 text-gray-500" />
            </motion.div>
          </CardTitle>
          <p className="text-xs sm:text-sm text-gray-600 mt-1">
            Specify roof details to help our AI focus on rooftop analysis and create more accurate solar panel placement recommendations
          </p>
        </CardHeader>
        <AnimatePresence>
          {isRoofDetailsOpen && (
            <motion.div
              initial={{ height: 0, opacity: 0 }}
              animate={{ height: "auto", opacity: 1 }}
              exit={{ height: 0, opacity: 0 }}
              transition={{ 
                duration: 0.4, 
                ease: "easeInOut",
                opacity: { duration: 0.3 }
              }}
              style={{ overflow: "hidden" }}
            >
              <CardContent className="pt-0 px-3 sm:px-6 pb-4 sm:pb-6">
                <motion.div 
                  className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-3 sm:gap-4 lg:gap-6 items-end"
                  initial={{ y: -20, opacity: 0 }}
                  animate={{ y: 0, opacity: 1 }}
                  transition={{ delay: 0.1, duration: 0.3 }}
                >
                  <motion.div 
                    className="space-y-2"
                    initial={{ y: 20, opacity: 0 }}
                    animate={{ y: 0, opacity: 1 }}
                    transition={{ delay: 0.15, duration: 0.3 }}
                  >
                    <Label htmlFor="roofSize" className="flex items-center gap-2 text-sm font-medium">
                      <Ruler className="w-4 h-4 text-blue-600" />
                      Roof Size (sq ft)
                    </Label>
                    <Input
                      id="roofSize"
                      type="number"
                      placeholder="e.g., 2000"
                      min="100"
                      max="10000"
                      value={roofInput.roofSize || ''}
                      onChange={(e) => setRoofInput({
                        ...roofInput,
                        roofSize: e.target.value ? parseInt(e.target.value) : undefined
                      })}
                      className="h-10 sm:h-11 text-sm"
                    />
                  </motion.div>

                  <motion.div 
                    className="space-y-2"
                    initial={{ y: 20, opacity: 0 }}
                    animate={{ y: 0, opacity: 1 }}
                    transition={{ delay: 0.2, duration: 0.3 }}
                  >
                    <Label htmlFor="roofShape" className="text-sm font-medium flex items-center gap-2">
                      <Home className="w-4 h-4 text-green-600" />
                      Roof Shape
                    </Label>
                    <Select 
                      value={roofInput.roofShape} 
                      onValueChange={(value) => setRoofInput({
                        ...roofInput,
                        roofShape: value as RoofInput['roofShape']
                      })}
                    >
                      <SelectTrigger className="h-10 sm:h-11 text-sm">
                        <SelectValue placeholder="Select roof shape" />
                      </SelectTrigger>
                      <SelectContent>
                        <SelectItem value="auto-detect">Auto-detect from image</SelectItem>
                        <SelectItem value="gable">Gable (Triangle)</SelectItem>
                        <SelectItem value="hip">Hip (Pyramid)</SelectItem>
                        <SelectItem value="shed">Shed (Single slope)</SelectItem>
                        <SelectItem value="flat">Flat</SelectItem>
                        <SelectItem value="complex">Complex/Mixed</SelectItem>
                      </SelectContent>
                    </Select>
                  </motion.div>

                  <motion.div 
                    className="space-y-2"
                    initial={{ y: 20, opacity: 0 }}
                    animate={{ y: 0, opacity: 1 }}
                    transition={{ delay: 0.25, duration: 0.3 }}
                  >
                    <Label htmlFor="panelSize" className="text-sm font-medium flex items-center gap-2">
                      <Settings className="w-4 h-4 text-orange-600" />
                      Panel Size Preference
                    </Label>
                    <Select 
                      value={roofInput.panelSize} 
                      onValueChange={(value) => setRoofInput({
                        ...roofInput,
                        panelSize: value as RoofInput['panelSize']
                      })}
                    >
                      <SelectTrigger className="h-10 sm:h-11 text-sm">
                        <SelectValue placeholder="Select panel size" />
                      </SelectTrigger>
                      <SelectContent>
                        <SelectItem value="auto-optimize">Auto-optimize for roof</SelectItem>
                        <SelectItem value="standard">Standard (425W)</SelectItem>
                        <SelectItem value="large">Large (500W+)</SelectItem>
                      </SelectContent>
                    </Select>
                  </motion.div>
                </motion.div>
              </CardContent>
            </motion.div>
          )}
        </AnimatePresence>
      </Card>

      <ImageUpload
        ref={imageUploadRef}
        onUpload={handleImageUpload}
        onAnalyze={handleAnalyze}
        uploading={analysisMutation.isPending}
        title="Upload Rooftop Image"
        description="Upload a clear image of your rooftop taken from above or at an angle. Our AI will analyze it and provide dynamic solar panel placement recommendations."
        validationType="installation"
      />

      {(analysisResult || analysisMutation.isPending) && (
        <div
          ref={resultsRef}
          className="grid grid-cols-1 xl:grid-cols-2 gap-4 sm:gap-6"
        >
            {/* Image Analysis Display */}
            <div className="order-1 xl:order-1">
              <Card className="shadow-material">
                <CardContent className="p-3 sm:p-4 lg:p-6">
                  <div className="flex items-center justify-between mb-3 sm:mb-4 lg:mb-6">
                    <h4 className="text-base sm:text-lg md:text-xl font-bold text-primary-custom">AI Analysis Results</h4>
                    {analysisResult && (
                      <Button
                        variant="outline"
                        size="sm"
                        onClick={() => {
                          // Clean up object URL to prevent memory leaks
                          if (imageUrl) {
                            URL.revokeObjectURL(imageUrl);
                          }

                          // Clear analysis result and image
                          setAnalysisResult(null);
                          setImageUrl(null);

                          // Reset the image uploader
                          if (imageUploadRef.current) {
                            imageUploadRef.current.reset();
                          }

                          // Clear sessionStorage
                          sessionStorage.removeItem('installationAnalysisResult');
                          sessionStorage.removeItem('installationImageUrl');
                          sessionStorage.removeItem('installationRoofInput');
                        }}
                        className="bg-white hover:bg-red-50 border-red-200 text-red-600 hover:text-red-700 p-2 h-8 rounded-md"
                        title="Clear analysis results"
                      >
                        <X size={14} />
                        <span className="ml-1 hidden sm:inline">Clear</span>
                      </Button>
                    )}
                  </div>

                  {analysisMutation.isPending ? (
                    <div className="bg-gray-100 rounded-lg flex items-center justify-center h-40 sm:h-48 md:h-56 lg:h-64">
                      <div className="text-center px-3 sm:px-4">
                        <div className="animate-spin rounded-full h-8 w-8 sm:h-10 sm:w-10 md:h-12 md:w-12 border-b-2 border-primary mx-auto mb-3 sm:mb-4"></div>
                        <p className="text-secondary-custom mb-3 sm:mb-4 text-xs sm:text-sm md:text-base">
                          Analyzing your rooftop...
                        </p>
                        <div className="w-32 sm:w-40 md:w-48 h-1.5 sm:h-2 bg-gray-200 rounded-full mx-auto mb-2">
                          <div className="h-1.5 sm:h-2 bg-primary rounded-full progress-animate"></div>
                        </div>
                        <p className="text-xs text-gray-500">AI processing in progress</p>
                      </div>
                    </div>
                  ) : (
                    <div className="relative">
                      <AnalysisOverlay
                        imageUrl={imageUrl || ''}
                        regions={analysisResult?.regions || []}
                        type="installation"
                        ref={analysisCanvasRef}
                      />
                      <div>
                        <Badge className="absolute top-2 right-2 bg-green-500 text-white text-xs sm:text-sm">
                          <CheckCircle className="mr-1" size={12} />
                          <span>Analysis Complete</span>
                        </Badge>
                      </div>
                    </div>
                  )}

                  {analysisResult && (
                    <div className="mt-3 sm:mt-4 flex justify-end">
                      <div className="text-xs sm:text-sm text-secondary-custom">
                        Confidence: {analysisResult.confidence}%
                      </div>
                    </div>
                  )}
                </CardContent>
              </Card>
            </div>

            {/* Installation Recommendations */}
            <div className="order-2 xl:order-2">
              <Card className="shadow-material">
                <CardContent className="p-3 sm:p-4 lg:p-6">
                  <h4 className="text-base sm:text-lg md:text-xl font-bold mb-3 sm:mb-4 text-primary-custom">Installation Recommendations</h4>

                  {analysisMutation.isPending ? (
                    <div className="space-y-3 sm:space-y-4">
                      <div className="grid grid-cols-1 sm:grid-cols-2 gap-3 sm:gap-4">
                        {[...Array(4)].map((_, i) => (
                          <div
                            key={i}
                            className="bg-gray-100 animate-pulse rounded-lg p-3 sm:p-4 h-12 sm:h-16"
                          />
                        ))}
                      </div>
                      <div className="space-y-2">
                        {[...Array(3)].map((_, i) => (
                          <div
                            key={i}
                            className="bg-gray-100 animate-pulse rounded h-3 sm:h-4"
                          />
                        ))}
                      </div>
                    </div>
                  ) : analysisResult && (
                    <div>
                      <div>
                      {/* Metrics Cards */}
                      <div className="grid grid-cols-1 sm:grid-cols-2 gap-2 sm:gap-3 md:gap-4 mb-4 sm:mb-6">
                        {[
                          { value: analysisResult.totalPanels, label: "Recommended Panels", color: "blue", bgColor: "bg-blue-50", textColor: "text-primary" },
                          { value: `${Math.round(Number(analysisResult.coverage))}%`, label: "Roof Coverage", color: "green", bgColor: "bg-green-50", textColor: "text-green-600" },
                          { value: `${analysisResult.efficiency}%`, label: "Efficiency Score", color: "orange", bgColor: "bg-orange-50", textColor: "text-orange-600" },
                          { value: `${Math.round(Number(analysisResult.powerOutput))}kW`, label: "Est. Power Output", color: "purple", bgColor: "bg-purple-50", textColor: "text-purple-600" }
                        ].map((metric, index) => (
                          <div
                            key={metric.label}
                            className={`${metric.bgColor} p-2 sm:p-3 md:p-4 rounded-lg hover:shadow-md transition-shadow cursor-pointer`}
                          >
                            <div className={`text-lg sm:text-xl md:text-2xl font-bold ${metric.textColor}`}>
                              {metric.value}
                            </div>
                            <div className="text-xs sm:text-sm text-secondary-custom">{metric.label}</div>
                          </div>
                        ))}
                      </div>

                  {/* Roof Area Information */}
                  {(analysisResult.estimatedRoofArea || analysisResult.usableRoofArea) && (
                    <div className="grid grid-cols-1 sm:grid-cols-2 gap-2 sm:gap-3 md:gap-4 mb-4 sm:mb-6">
                      {analysisResult.estimatedRoofArea && (
                        <div className="bg-slate-50 p-2 sm:p-3 md:p-4 rounded-lg hover:shadow-md transition-shadow cursor-pointer">
                          <div className="text-lg sm:text-xl md:text-2xl font-bold text-slate-700">{analysisResult.estimatedRoofArea}</div>
                          <div className="text-xs sm:text-sm text-secondary-custom">Total Roof Area (sq ft)</div>
                        </div>
                      )}
                      {analysisResult.usableRoofArea && (
                        <div className="bg-cyan-50 p-2 sm:p-3 md:p-4 rounded-lg hover:shadow-md transition-shadow cursor-pointer">
                          <div className="text-lg sm:text-xl md:text-2xl font-bold text-cyan-700">{analysisResult.usableRoofArea}</div>
                          <div className="text-xs sm:text-sm text-secondary-custom">Usable Area (sq ft)</div>
                        </div>
                      )}
                    </div>
                  )}

                  {/* Technical Details */}
                  <div className="space-y-3 sm:space-y-4">
                    <div className="border-l-4 border-green-500 pl-3 sm:pl-4">
                      <h5 className="font-medium text-sm sm:text-base text-primary-custom">Optimal Orientation</h5>
                      <p className="text-xs sm:text-sm text-secondary-custom">{analysisResult.orientation}</p>
                    </div>
                    <div className="border-l-4 border-blue-500 pl-3 sm:pl-4">
                      <h5 className="font-medium text-sm sm:text-base text-primary-custom">Shading Analysis</h5>
                      <p className="text-xs sm:text-sm text-secondary-custom">{analysisResult.shadingAnalysis}</p>
                    </div>
                    <div className="border-l-4 border-orange-500 pl-3 sm:pl-4">
                      <h5 className="font-medium text-sm sm:text-base text-primary-custom">Installation Notes</h5>
                      <div className="text-xs sm:text-sm text-secondary-custom">
                        {analysisResult.notes.split('\n')
                          .filter(line => line.trim() !== '' && !line.includes('Installation Notes') && !line.includes('Installation notes:')) // Remove duplicate heading and empty lines
                          .map((line, index) => {
                          // Handle markdown bold text
                          if (line.includes('**') && !line.startsWith('*')) {
                            const parts = line.split('**');
                            return (
                              <div key={index} className="mb-2 text-gray-700">
                                {parts.map((part, i) => 
                                  i % 2 === 1 ? <strong key={i} className="font-semibold text-primary-custom">{part}</strong> : part
                                )}
                              </div>
                            );
                          }
                          // Handle bullet points
                          if (line.startsWith('*') && !line.startsWith('**')) {
                            return (
                              <div key={index} className="ml-2 mb-1 flex items-start">
                                <span className="text-blue-500 mr-2 font-medium">•</span>
                                <span className="flex-1">{line.substring(1).trim()}</span>
                              </div>
                            );
                          }
                          // Handle section headers
                          if (line.startsWith('**') && line.endsWith('**') && !line.includes(':')) {
                            return (
                              <h6 key={index} className="font-semibold text-primary-custom mt-4 mb-2 text-base">
                                {line.replace(/\*\*/g, '')}
                              </h6>
                            );
                          }
                          // Handle normal text
                          return (
                            <div key={index} className="mb-1 text-gray-700">
                              {line}
                            </div>
                          );
                        })}
                      </div>
                    </div>


                  </div>

                      {/* Action Buttons */}
                      <div className="mt-4 sm:mt-6 flex flex-col sm:flex-row space-y-2 sm:space-y-0 sm:space-x-3">
                        <Button className="flex-1 bg-green-600 hover:bg-green-700 text-white text-sm h-10" onClick={exportCompletePDF}>
                          <FileDown className="mr-1 sm:mr-2" size={14} />
                          <div className="text-left">
                            <div className="font-medium">Complete Report</div>
                            <div className="text-xs opacity-90">Full analysis PDF</div>
                          </div>
                        </Button>
                        <Button 
                          variant="outline" 
                          className="flex-1 bg-gradient-to-r from-blue-50 to-indigo-50 border-blue-200 hover:shadow-lg hover:bg-white text-sm h-10 shadow-md text-black hover:text-black" 
                          onClick={exportQuickSummaryPDF}
                        >
                          <svg className="mr-1 sm:mr-2" width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2">
                            <path d="M14 2H6a2 2 0 0 0-2 2v16a2 2 0 0 0 2 2h12a2 2 0 0 0 2-2V8z"></path>
                            <polyline points="14,2 14,8 20,8"></polyline>
                            <line x1="16" y1="13" x2="8" y2="13"></line>
                            <line x1="16" y1="17" x2="8" y2="17"></line>
                            <polyline points="10,9 9,9 8,9"></polyline>
                          </svg>
                          <div className="text-left">
                            <div className="font-medium">Quick Summary</div>
                            <div className="text-xs opacity-70">Essential details</div>
                          </div>
                        </Button>
                      </div>
                    </div>
                    </div>
                  )}
                </CardContent>
              </Card>
            </div>
          </div>
        )}
    </div>
  );
}

client/src/components/live-demo-dashboar.content:
import { useState, useEffect } from "react";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from "@/components/ui/select";
import { Badge } from "@/components/ui/badge";
import { Progress } from "@/components/ui/progress";
import { Tabs, TabsContent, TabsList, TabsTrigger } from "@/components/ui/tabs";
import { 
  Cloud, 
  Sun, 
  CloudRain, 
  Zap, 
  ZapOff, 
  Battery, 
  Activity,
  AlertTriangle,
  CheckCircle,
  Play,
  Square,
  RefreshCw
} from "lucide-react";
import { useQuery, useMutation, useQueryClient } from "@tanstack/react-query";
import { useToast } from "@/hooks/use-toast";

interface WeatherCondition {
  condition: string;
  temperature: number;
  cloudCover: number;
  windSpeed: number;
}

interface SimulationStatus {
  isRunning: boolean;
  currentWeather: WeatherCondition;
  activeOutages: number[];
  networkStats: {
    totalHouseholds: number;
    activeConnections: number;
    totalGeneration: number;
    totalConsumption: number;
    batteryStorageTotal: number;
    tradingVelocity: number;
    carbonReduction: number;
  };
}

interface OptimizationResult {
  success: boolean;
  optimization: {
    gridStability: string;
    recommendations: string[];
    gridBalancing?: {
      supplyDemandRatio: number;
      gridLoadFactor: number;
      loadSheddingRequired: boolean;
    };
    equitableAccess?: {
      averageEnergySecurity: number;
      vulnerableHouseholds: number[];
      equityScore: number;
    };
  };
  networkHealth?: string;
}

export function LiveDemoDashboard() {
  const { toast } = useToast();
  const queryClient = useQueryClient();
  const [selectedWeather, setSelectedWeather] = useState<string>("");

  // Query simulation status
  const { data: simulationStatus } = useQuery<SimulationStatus>({
    queryKey: ["/api/simulation/status"],
    refetchInterval: 3000, // Refresh every 3 seconds for live demo
  });

  // Query ML optimization
  const { data: optimization } = useQuery<OptimizationResult>({
    queryKey: ["/api/ml/optimization"],
    refetchInterval: 5000, // Refresh every 5 seconds
  });

  // Query network analytics
  const { data: networkAnalytics } = useQuery({
    queryKey: ["/api/analytics/network"],
    refetchInterval: 4000,
  });

  // Start simulation mutation
  const startSimulationMutation = useMutation({
    mutationFn: async () => {
      const response = await fetch("/api/simulation/start", { method: "POST" });
      if (!response.ok) throw new Error("Failed to start simulation");
      return response.json();
    },
    onSuccess: (data) => {
      toast({
        title: "Live Demonstration Started",
        description: "Automatic energy flow management system is now running",
      });
      queryClient.invalidateQueries({ queryKey: ["/api/simulation/status"] });
    },
  });

  // Stop simulation mutation
  const stopSimulationMutation = useMutation({
    mutationFn: async () => {
      const response = await fetch("/api/simulation/stop", { method: "POST" });
      if (!response.ok) throw new Error("Failed to stop simulation");
      return response.json();
    },
    onSuccess: () => {
      toast({
        title: "Simulation Stopped",
        description: "Live demonstration has been stopped",
      });
      queryClient.invalidateQueries({ queryKey: ["/api/simulation/status"] });
    },
  });

  // Weather change mutation
  const changeWeatherMutation = useMutation({
    mutationFn: async (condition: string) => {
      const response = await fetch("/api/simulation/weather", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ condition }),
      });
      if (!response.ok) throw new Error("Failed to change weather");
      return response.json();
    },
    onSuccess: (data) => {
      toast({
        title: "Weather Changed",
        description: data.message,
      });
      queryClient.invalidateQueries({ queryKey: ["/api/simulation/status"] });
      queryClient.invalidateQueries({ queryKey: ["/api/ml/optimization"] });
    },
  });

  // Outage simulation mutation
  const triggerOutageMutation = useMutation({
    mutationFn: async () => {
      const response = await fetch("/api/simulation/outage", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ householdIds: [] }), // Random outage
      });
      if (!response.ok) throw new Error("Failed to trigger outage");
      return response.json();
    },
    onSuccess: (data) => {
      toast({
        title: "Power Outage Simulation",
        description: data.message,
      });
      queryClient.invalidateQueries({ queryKey: ["/api/simulation/status"] });
    },
  });

  const getWeatherIcon = (condition: string) => {
    switch (condition) {
      case "sunny": return <Sun className="h-6 w-6 text-yellow-500" />;
      case "cloudy": 
      case "overcast": return <Cloud className="h-6 w-6 text-gray-500" />;
      case "rainy": 
      case "stormy": return <CloudRain className="h-6 w-6 text-blue-500" />;
      default: return <Sun className="h-6 w-6 text-yellow-500" />;
    }
  };

  const getGridStabilityColor = (stability: string) => {
    const value = parseFloat(stability);
    if (value > 90) return "text-green-600";
    if (value > 75) return "text-yellow-600";
    return "text-red-600";
  };

  return (
    <div className="space-y-6" data-testid="live-demo-dashboard">
      {/* Control Panel */}
      <Card>
        <CardHeader>
          <CardTitle className="flex items-center gap-2">
            <Activity className="h-5 w-5" />
            Live Demonstration Control Panel
          </CardTitle>
        </CardHeader>
        <CardContent className="space-y-4">
          <div className="flex items-center gap-4">
            <div className="flex items-center gap-2">
              <Badge 
                variant={simulationStatus?.isRunning ? "default" : "secondary"}
                data-testid="simulation-status-badge"
              >
                {simulationStatus?.isRunning ? (
                  <>
                    <Play className="h-3 w-3 mr-1" />
                    Running
                  </>
                ) : (
                  <>
                    <Square className="h-3 w-3 mr-1" />
                    Stopped
                  </>
                )}
              </Badge>
            </div>

            <Button
              onClick={() => startSimulationMutation.mutate()}
              disabled={simulationStatus?.isRunning || startSimulationMutation.isPending}
              size="sm"
              data-testid="button-start-simulation"
            >
              {startSimulationMutation.isPending ? (
                <RefreshCw className="h-4 w-4 animate-spin mr-2" />
              ) : (
                <Play className="h-4 w-4 mr-2" />
              )}
              Start Live Demo
            </Button>

            <Button
              onClick={() => stopSimulationMutation.mutate()}
              disabled={!simulationStatus?.isRunning || stopSimulationMutation.isPending}
              variant="outline"
              size="sm"
              data-testid="button-stop-simulation"
            >
              <Square className="h-4 w-4 mr-2" />
              Stop Demo
            </Button>
          </div>

          {simulationStatus?.isRunning && (
            <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
              {/* Weather Control */}
              <div className="space-y-2">
                <label className="text-sm font-medium">Test Weather Adaptation</label>
                <div className="flex gap-2">
                  <Select
                    value={selectedWeather}
                    onValueChange={setSelectedWeather}
                    data-testid="select-weather-condition"
                  >
                    <SelectTrigger className="flex-1">
                      <SelectValue placeholder="Select weather condition" />
                    </SelectTrigger>
                    <SelectContent>
                      <SelectItem value="sunny">☀️ Sunny</SelectItem>
                      <SelectItem value="partly-cloudy">⛅ Partly Cloudy</SelectItem>
                      <SelectItem value="cloudy">☁️ Cloudy</SelectItem>
                      <SelectItem value="overcast">☁️ Overcast</SelectItem>
                      <SelectItem value="rainy">🌧️ Rainy</SelectItem>
                      <SelectItem value="stormy">⛈️ Stormy</SelectItem>
                    </SelectContent>
                  </Select>
                  <Button
                    onClick={() => selectedWeather && changeWeatherMutation.mutate(selectedWeather)}
                    disabled={!selectedWeather || changeWeatherMutation.isPending}
                    size="sm"
                    data-testid="button-change-weather"
                  >
                    Apply
                  </Button>
                </div>
              </div>

              {/* Outage Simulation */}
              <div className="space-y-2">
                <label className="text-sm font-medium">Test Power Outage Response</label>
                <Button
                  onClick={() => triggerOutageMutation.mutate()}
                  disabled={triggerOutageMutation.isPending}
                  variant="outline"
                  size="sm"
                  data-testid="button-trigger-outage"
                >
                  {triggerOutageMutation.isPending ? (
                    <RefreshCw className="h-4 w-4 animate-spin mr-2" />
                  ) : (
                    <ZapOff className="h-4 w-4 mr-2" />
                  )}
                  Simulate Outage
                </Button>
              </div>
            </div>
          )}
        </CardContent>
      </Card>

      {/* Live Status Display */}
      <Tabs defaultValue="overview" className="space-y-4">
        <TabsList className="grid w-full grid-cols-4">
          <TabsTrigger value="overview">Overview</TabsTrigger>
          <TabsTrigger value="weather">Weather Impact</TabsTrigger>
          <TabsTrigger value="grid">Grid Management</TabsTrigger>
          <TabsTrigger value="equity">Equitable Access</TabsTrigger>
        </TabsList>

        <TabsContent value="overview" className="space-y-4">
          <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-4">
            <Card data-testid="card-total-households">
              <CardContent className="pt-6">
                <div className="flex items-center justify-between">
                  <div>
                    <p className="text-sm text-muted-foreground">Total Households</p>
                    <p className="text-2xl font-bold" data-testid="text-total-households">
                      {(networkAnalytics as any)?.network?.totalHouseholds || 0}
                    </p>
                  </div>
                  <Activity className="h-8 w-8 text-muted-foreground" />
                </div>
              </CardContent>
            </Card>

            <Card data-testid="card-active-connections">
              <CardContent className="pt-6">
                <div className="flex items-center justify-between">
                  <div>
                    <p className="text-sm text-muted-foreground">Active Connections</p>
                    <p className="text-2xl font-bold text-green-600" data-testid="text-active-connections">
                      {(networkAnalytics as any)?.network?.activeHouseholds || 0}
                    </p>
                  </div>
                  <CheckCircle className="h-8 w-8 text-green-500" />
                </div>
              </CardContent>
            </Card>

            <Card data-testid="card-grid-stability">
              <CardContent className="pt-6">
                <div className="flex items-center justify-between">
                  <div>
                    <p className="text-sm text-muted-foreground">Grid Stability</p>
                    <p className={`text-2xl font-bold ${getGridStabilityColor(optimization?.optimization?.gridStability || "0%")}`} data-testid="text-grid-stability">
                      {optimization?.optimization?.gridStability || "N/A"}
                    </p>
                  </div>
                  <Zap className="h-8 w-8 text-muted-foreground" />
                </div>
              </CardContent>
            </Card>

            <Card data-testid="card-storage-capacity">
              <CardContent className="pt-6">
                <div className="flex items-center justify-between">
                  <div>
                    <p className="text-sm text-muted-foreground">Storage Capacity</p>
                    <p className="text-2xl font-bold" data-testid="text-storage-capacity">
                      {(networkAnalytics as any)?.network?.totalStorageCapacity || "0 kWh"}
                    </p>
                  </div>
                  <Battery className="h-8 w-8 text-muted-foreground" />
                </div>
              </CardContent>
            </Card>
          </div>
        </TabsContent>

        <TabsContent value="weather" className="space-y-4">
          <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
            <Card data-testid="card-current-weather">
              <CardHeader>
                <CardTitle className="flex items-center gap-2">
                  {getWeatherIcon(simulationStatus?.currentWeather?.condition || "sunny")}
                  Current Weather Conditions
                </CardTitle>
              </CardHeader>
              <CardContent className="space-y-4">
                <div className="space-y-2">
                  <div className="flex justify-between">
                    <span>Condition:</span>
                    <Badge data-testid="badge-weather-condition">
                      {simulationStatus?.currentWeather?.condition || "sunny"}
                    </Badge>
                  </div>
                  <div className="flex justify-between">
                    <span>Temperature:</span>
                    <span data-testid="text-temperature">{simulationStatus?.currentWeather?.temperature || 25}°C</span>
                  </div>
                  <div className="flex justify-between">
                    <span>Cloud Cover:</span>
                    <span data-testid="text-cloud-cover">{simulationStatus?.currentWeather?.cloudCover || 20}%</span>
                  </div>
                </div>
                <div className="space-y-2">
                  <label className="text-sm font-medium">Solar Generation Impact</label>
                  <Progress 
                    value={simulationStatus?.currentWeather?.condition === 'sunny' ? 100 : 
                           simulationStatus?.currentWeather?.condition === 'partly-cloudy' ? 82 :
                           simulationStatus?.currentWeather?.condition === 'cloudy' ? 45 :
                           simulationStatus?.currentWeather?.condition === 'rainy' ? 15 : 60} 
                    className="w-full" 
                    data-testid="progress-solar-impact"
                  />
                </div>
              </CardContent>
            </Card>

            <Card data-testid="card-weather-adaptation">
              <CardHeader>
                <CardTitle>Weather Adaptation Strategy</CardTitle>
              </CardHeader>
              <CardContent>
                <div className="space-y-2">
                  {optimization?.optimization?.recommendations?.slice(0, 3).map((recommendation, index) => (
                    <div key={index} className="flex items-start gap-2" data-testid={`recommendation-${index}`}>
                      <CheckCircle className="h-4 w-4 text-green-500 mt-0.5 flex-shrink-0" />
                      <span className="text-sm">{recommendation}</span>
                    </div>
                  )) || (
                    <p className="text-sm text-muted-foreground">Loading weather adaptation strategies...</p>
                  )}
                </div>
              </CardContent>
            </Card>
          </div>
        </TabsContent>

        <TabsContent value="grid" className="space-y-4">
          <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
            <Card data-testid="card-load-balancing">
              <CardHeader>
                <CardTitle>Automatic Load Balancing</CardTitle>
              </CardHeader>
              <CardContent className="space-y-4">
                <div className="space-y-2">
                  <div className="flex justify-between">
                    <span>Supply/Demand Ratio:</span>
                    <span className="font-mono" data-testid="text-supply-demand-ratio">
                      {optimization?.optimization?.gridBalancing?.supplyDemandRatio?.toFixed(2) || "1.00"}
                    </span>
                  </div>
                  <div className="flex justify-between">
                    <span>Grid Load Factor:</span>
                    <span className="font-mono" data-testid="text-grid-load-factor">
                      {((optimization?.optimization?.gridBalancing?.gridLoadFactor || 0) * 100).toFixed(1)}%
                    </span>
                  </div>
                  <div className="flex justify-between">
                    <span>Load Shedding:</span>
                    <Badge variant={optimization?.optimization?.gridBalancing?.loadSheddingRequired ? "destructive" : "default"} data-testid="badge-load-shedding">
                      {optimization?.optimization?.gridBalancing?.loadSheddingRequired ? "Required" : "Not Required"}
                    </Badge>
                  </div>
                </div>
              </CardContent>
            </Card>

            <Card data-testid="card-outage-response">
              <CardHeader>
                <CardTitle>Outage Response System</CardTitle>
              </CardHeader>
              <CardContent className="space-y-4">
                {simulationStatus?.activeOutages && simulationStatus.activeOutages.length > 0 ? (
                  <div className="space-y-2">
                    <div className="flex items-center gap-2">
                      <AlertTriangle className="h-4 w-4 text-red-500" />
                      <span className="text-sm font-medium" data-testid="text-active-outages">
                        {simulationStatus.activeOutages.length} households affected
                      </span>
                    </div>
                    <p className="text-sm text-muted-foreground">
                      Automatic energy redistribution in progress...
                    </p>
                  </div>
                ) : (
                  <div className="space-y-2">
                    <div className="flex items-center gap-2">
                      <CheckCircle className="h-4 w-4 text-green-500" />
                      <span className="text-sm font-medium" data-testid="text-no-outages">All systems operational</span>
                    </div>
                    <p className="text-sm text-muted-foreground">
                      Network resilience system standing by
                    </p>
                  </div>
                )}
              </CardContent>
            </Card>
          </div>
        </TabsContent>

        <TabsContent value="equity" className="space-y-4">
          <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
            <Card data-testid="card-energy-security">
              <CardHeader>
                <CardTitle>Energy Security Analysis</CardTitle>
              </CardHeader>
              <CardContent className="space-y-4">
                <div className="space-y-2">
                  <div className="flex justify-between">
                    <span>Average Energy Security:</span>
                    <span className="font-mono" data-testid="text-avg-energy-security">
                      {((optimization?.optimization?.equitableAccess?.averageEnergySecurity || 0) * 100).toFixed(1)}%
                    </span>
                  </div>
                  <div className="flex justify-between">
                    <span>Vulnerable Households:</span>
                    <span className="font-mono" data-testid="text-vulnerable-households">
                      {optimization?.optimization?.equitableAccess?.vulnerableHouseholds?.length || 0}
                    </span>
                  </div>
                  <div className="flex justify-between">
                    <span>Equity Score:</span>
                    <span className="font-mono" data-testid="text-equity-score">
                      {((optimization?.optimization?.equitableAccess?.equityScore || 0) * 100).toFixed(1)}%
                    </span>
                  </div>
                </div>
              </CardContent>
            </Card>

            <Card data-testid="card-redistribution">
              <CardHeader>
                <CardTitle>Energy Redistribution</CardTitle>
              </CardHeader>
              <CardContent>
                <div className="space-y-2">
                  <div className="flex items-center gap-2">
                    <Activity className="h-4 w-4 text-blue-500" />
                    <span className="text-sm font-medium">Automatic Fair Distribution Active</span>
                  </div>
                  <p className="text-sm text-muted-foreground">
                    System ensures equitable access to power across all households
                  </p>
                  <div className="mt-4">
                    <Progress 
                      value={((optimization?.optimization?.equitableAccess?.equityScore || 0) * 100)} 
                      className="w-full" 
                      data-testid="progress-equity-score"
                    />
                    <p className="text-xs text-muted-foreground mt-1">Equity Score</p>
                  </div>
                </div>
              </CardContent>
            </Card>
          </div>
        </TabsContent>
      </Tabs>

      {/* Status Message */}
      {optimization?.networkHealth && (
        <Card data-testid="card-network-health">
          <CardContent className="pt-6">
            <div className="flex items-center gap-2">
              <CheckCircle className="h-5 w-5 text-green-500" />
              <span className="text-sm font-medium" data-testid="text-network-health">
                {optimization.networkHealth}
              </span>
            </div>
          </CardContent>
        </Card>
      )}
    </div>
  );
}

client/src/components/location-request.t.content:
import { useState, useEffect } from 'react';
import { Button } from '@/components/ui/button';
import { Dialog, DialogContent, DialogDescription, DialogHeader, DialogTitle } from '@/components/ui/dialog';
import { Alert, AlertDescription } from '@/components/ui/alert';
import { MapPin, Shield, Zap, CheckCircle, XCircle, AlertCircle } from 'lucide-react';
import { locationService, UserLocation, LocationError } from '@/lib/location-service';

interface LocationRequestProps {
  onLocationGranted: (location: UserLocation) => void;
  onLocationDenied: () => void;
  isOpen: boolean;
}

export function LocationRequest({ onLocationGranted, onLocationDenied, isOpen }: LocationRequestProps) {
  const [isRequestingLocation, setIsRequestingLocation] = useState(false);
  const [locationError, setLocationError] = useState<LocationError | null>(null);
  const [showPermissionDialog, setShowPermissionDialog] = useState(isOpen);

  useEffect(() => {
    setShowPermissionDialog(isOpen);
  }, [isOpen]);

  const handleLocationRequest = async () => {
    setIsRequestingLocation(true);
    setLocationError(null);

    try {
      const location = await locationService.getCurrentLocation(true);
      onLocationGranted(location);
      setShowPermissionDialog(false);
    } catch (error: any) {
      setLocationError(error as LocationError);
      if (error.type === 'permission_denied') {
        onLocationDenied();
      }
    } finally {
      setIsRequestingLocation(false);
    }
  };

  const handleSkip = () => {
    setShowPermissionDialog(false);
    onLocationDenied();
  };

  const getErrorMessage = (error: LocationError): string => {
    switch (error.type) {
      case 'permission_denied':
        return 'Location access was denied. Please enable location permissions in your browser settings to get localized energy data.';
      case 'position_unavailable':
        return 'Your location could not be determined. Please check your internet connection and try again.';
      case 'timeout':
        return 'Location request timed out. Please try again.';
      default:
        return 'An error occurred while getting your location. Please try again.';
    }
  };

  return (
    <Dialog open={showPermissionDialog} onOpenChange={() => {}}>
      <DialogContent className="sm:max-w-md" data-testid="dialog-location-permission">
        <DialogHeader>
          <DialogTitle className="flex items-center gap-2" data-testid="text-dialog-title">
            <MapPin className="h-5 w-5 text-blue-500" />
            Share Your Location
          </DialogTitle>
          <DialogDescription data-testid="text-dialog-description">
            SolarSense would like to access your precise location to provide personalized energy trading opportunities and localized renewable energy data.
          </DialogDescription>
        </DialogHeader>

        <div className="space-y-4">
          <div className="grid grid-cols-1 gap-3">
            <div className="flex items-start gap-3 p-3 bg-blue-50 dark:bg-blue-950/50 rounded-lg">
              <Zap className="h-4 w-4 text-blue-500 mt-0.5" />
              <div>
                <p className="text-sm font-medium text-blue-700 dark:text-blue-300">
                  Local Energy Network
                </p>
                <p className="text-xs text-blue-600 dark:text-blue-400">
                  Find nearby solar installations and energy trading partners
                </p>
              </div>
            </div>

            <div className="flex items-start gap-3 p-3 bg-green-50 dark:bg-green-950/50 rounded-lg">
              <Shield className="h-4 w-4 text-green-500 mt-0.5" />
              <div>
                <p className="text-sm font-medium text-green-700 dark:text-green-300">
                  Weather & Efficiency
                </p>
                <p className="text-xs text-green-600 dark:text-green-400">
                  Get accurate solar generation forecasts for your area
                </p>
              </div>
            </div>

            <div className="flex items-start gap-3 p-3 bg-purple-50 dark:bg-purple-950/50 rounded-lg">
              <CheckCircle className="h-4 w-4 text-purple-500 mt-0.5" />
              <div>
                <p className="text-sm font-medium text-purple-700 dark:text-purple-300">
                  Privacy Protected
                </p>
                <p className="text-xs text-purple-600 dark:text-purple-400">
                  Your exact location is never shared with other users
                </p>
              </div>
            </div>
          </div>

          {locationError && (
            <Alert className="border-red-200 bg-red-50 dark:bg-red-950/50" data-testid="alert-location-error">
              <AlertCircle className="h-4 w-4 text-red-500" />
              <AlertDescription className="text-red-700 dark:text-red-300">
                {getErrorMessage(locationError)}
              </AlertDescription>
            </Alert>
          )}

          <div className="flex gap-2 pt-2">
            <Button
              onClick={handleLocationRequest}
              disabled={isRequestingLocation}
              className="flex-1"
              data-testid="button-allow-location"
            >
              {isRequestingLocation ? (
                <>
                  <div className="animate-spin rounded-full h-4 w-4 border-2 border-white border-t-transparent mr-2" />
                  Getting Location...
                </>
              ) : (
                <>
                  <MapPin className="h-4 w-4 mr-2" />
                  Allow Location
                </>
              )}
            </Button>

            <Button
              variant="outline"
              onClick={handleSkip}
              disabled={isRequestingLocation}
              className="flex-1"
              data-testid="button-skip-location"
            >
              <XCircle className="h-4 w-4 mr-2" />
              Skip for Now
            </Button>
          </div>

          <p className="text-xs text-muted-foreground text-center" data-testid="text-privacy-note">
            You can change this permission later in your browser settings
          </p>
        </div>
      </DialogContent>
    </Dialog>
  );
}

