import { motion } from "framer-motion";
import { CheckCircle, XCircle, AlertTriangle, Info, Loader2, X } from "lucide-react";
import { cn } from "@/lib/utils";

interface ValidationCardProps {
  type: "validating" | "success" | "error" | "warning" | "info";
  title: string;
  description: string;
  className?: string;
  onClose?: () => void;
}

export default function ValidationCard({ type, title, description, className, onClose }: ValidationCardProps) {
  const getIcon = () => {
    switch (type) {
      case "validating":
        return <Loader2 className="h-5 w-5 animate-spin text-blue-600" />;
      case "success":
        return <CheckCircle className="h-5 w-5 text-green-600" />;
      case "error":
        return <XCircle className="h-5 w-5 text-red-600" />;
      case "warning":
        return <AlertTriangle className="h-5 w-5 text-orange-600" />;
      case "info":
        return <Info className="h-5 w-5 text-blue-600" />;
      default:
        return <Info className="h-5 w-5 text-blue-600" />;
    }
  };

  const getStyles = () => {
    switch (type) {
      case "validating":
        return "bg-white border-blue-200 shadow-lg";
      case "success":
        return "bg-white border-green-200 shadow-lg";
      case "error":
        return "bg-white border-red-200 shadow-lg";
      case "warning":
        return "bg-white border-orange-200 shadow-lg";
      case "info":
        return "bg-white border-blue-200 shadow-lg";
      default:
        return "bg-white border-gray-200 shadow-lg";
    }
  };

  const getTitleColor = () => {
    switch (type) {
      case "validating":
        return "text-blue-700";
      case "success":
        return "text-green-700";
      case "error":
        return "text-red-700";
      case "warning":
        return "text-orange-700";
      case "info":
        return "text-blue-700";
      default:
        return "text-gray-700";
    }
  };

  const getAnimationDirection = () => {
    switch (type) {
      case "success":
        return { x: 100 }; // Slide from right
      case "error":
        return { x: 100 }; // Slide from right
      case "warning":
        return { x: 100 }; // Slide from right
      case "info":
        return { x: 100 }; // Slide from right
      case "validating":
        return { x: 100 }; // Slide from right
      default:
        return { x: 100 };
    }
  };

  const getPosition = () => {
    switch (type) {
      case "success":
        return "top-4 right-4";
      case "error":
        return "top-4 right-4";
      case "warning":
        return "top-4 right-4";
      case "info":
        return "top-4 right-4";
      case "validating":
        return "top-4 right-4";
      default:
        return "top-4 right-4";
    }
  };

  return (
    <motion.div
      initial={{ opacity: 0, ...getAnimationDirection() }}
      animate={{ opacity: 1, x: 0, y: 0, scale: 1 }}
      exit={{ opacity: 0, ...getAnimationDirection() }}
      transition={{ 
        duration: 0.5,
        type: "spring",
        stiffness: 300,
        damping: 30
      }}
      className={cn(
        "fixed z-[10002] rounded-lg border-2 p-3 sm:p-4 max-w-xs sm:max-w-sm shadow-xl select-none",
        getPosition(),
        getStyles(),
        className
      )}
      onMouseEnter={(e) => e.stopPropagation()}
      onMouseLeave={(e) => e.stopPropagation()}
      onClick={(e) => e.stopPropagation()}
    >
      <div className="flex items-start space-x-2 sm:space-x-3">
        <div className="flex-shrink-0">
          {getIcon()}
        </div>
        <div className="flex-1 min-w-0">
          <h3 className={cn("text-sm sm:text-base font-semibold", getTitleColor())}>
            {title}
          </h3>
          <p className="mt-1 text-xs sm:text-sm text-gray-600 leading-relaxed">
            {description}
          </p>
        </div>
        {onClose && (
          <button
            onClick={(e) => {
              e.stopPropagation();
              onClose();
            }}
            className="absolute top-2 right-2 rounded-full p-1 hover:bg-gray-100 transition-colors"
          >
            <X className="h-3 w-3 sm:h-4 sm:w-4 text-gray-500" />
          </button>
        )}
      </div>
    </motion.div>
  );
}

client/src/hooks/use-auth.tsx.content:
import { createContext, ReactNode, useContext, useState, useEffect } from "react";
import {
  useQuery,
  useMutation,
  UseMutationResult,
  useQueryClient,
} from "@tanstack/react-query";
import { User, loginSchema, signupSchema } from "@shared/schema";
import { apiRequest } from "@/lib/queryClient";
import { useToast } from "@/hooks/use-toast";
import { z } from "zod";
import { checkServerHealth, HealthStatus } from "@/lib/health-check";

type AuthContextType = {
  user: User | null;
  isLoading: boolean;
  error: Error | null;
  loginMutation: UseMutationResult<any, Error, z.infer<typeof loginSchema>>;
  logoutMutation: UseMutationResult<void, Error, void>;
  registerMutation: UseMutationResult<any, Error, z.infer<typeof signupSchema>>;
  healthStatus: HealthStatus | null;
  checkHealth: () => Promise<HealthStatus | void>;
};

export const AuthContext = createContext<AuthContextType | null>(null);

export function AuthProvider({ children }: { children: ReactNode }) {
  const { toast } = useToast();
  const queryClient = useQueryClient();
  const [healthStatus, setHealthStatus] = useState<HealthStatus | null>(null);

  // Check server health on component mount
  const checkHealth = async () => {
    const status = await checkServerHealth();
    setHealthStatus(status);
    return status;
  };

  useEffect(() => {
    checkHealth();

    // Check server health every 30 seconds
    const healthCheckInterval = setInterval(() => {
      checkHealth();
    }, 30000);

    return () => clearInterval(healthCheckInterval);
  }, []);

  const {
    data: user,
    error,
    isLoading,
  } = useQuery({
    queryKey: ["/api/user"],
    queryFn: async () => {
      try {
        const response = await apiRequest("GET", "/api/user");
        if (response.status === 401) {
          return null;
        }
        const data = await response.json();
        return data.user;
      } catch (error) {
        // Silently return null for authentication failures
        // No server health checks or toast notifications
        return null;
      }
    },
    retry: false,
  });

  const loginMutation = useMutation({
    mutationFn: async (credentials: z.infer<typeof loginSchema>) => {
      const response = await apiRequest("POST", "/api/login", credentials);
      if (!response.ok) {
        const errorData = await response.json();
        throw new Error(errorData.error || "Login failed");
      }
      return await response.json();
    },
    onSuccess: (data) => {
      queryClient.setQueryData(["/api/user"], data.user);
      // Remove success toast to prevent duplicate notifications
      // Success handling is done in the component
    },
    onError: (error: Error) => {
      // Remove toast notification to prevent duplicate validation
      // Error handling is now done in the component ValidationCard
    },
  });

  const registerMutation = useMutation({
    mutationFn: async (credentials: z.infer<typeof signupSchema>) => {
      const response = await apiRequest("POST", "/api/register", credentials);
      if (!response.ok) {
        const errorData = await response.json();
        throw new Error(errorData.error || "Registration failed");
      }
      return await response.json();
    },
    onSuccess: (data) => {
      queryClient.setQueryData(["/api/user"], data.user);
      // Remove success toast to prevent duplicate notifications
      // Success handling is done in the component
    },
    onError: (error: Error) => {
      // Remove toast notification to prevent duplicate validation
      // Error handling is now done in the component ValidationCard
    },
  });

  const logoutMutation = useMutation({
    mutationFn: async () => {
      await apiRequest("POST", "/api/logout");
    },
    onSuccess: () => {
      // Clear all authentication data
      queryClient.setQueryData(["/api/user"], null);

      // Clear all cached queries to force fresh data on next login
      queryClient.clear();

      // Clear any stored user data from localStorage/sessionStorage
      localStorage.removeItem("authToken");
      sessionStorage.clear();

      // Show logout success message in localStorage before redirect
      localStorage.setItem("logoutSuccess", "true");

      // Redirect to dashboard instead of reloading
      window.location.href = "/";
    },
    onError: (error: Error) => {
      // Show validation card for logout errors
      toast({
        title: "Logout failed",
        description: "Server is down. Please try again later.",
        variant: "destructive",
      });
    },
  });

  return (
    <AuthContext.Provider
      value={{
        user: user ?? null,
        isLoading,
        error,
        loginMutation,
        logoutMutation,
        registerMutation,
        healthStatus,
        checkHealth,
      }}
    >
      {children}
    </AuthContext.Provider>
  );
}

export function useAuth() {
  const context = useContext(AuthContext);
  if (!context) {
    throw new Error("useAuth must be used within an AuthProvider");
  }
  return context;
}

client/src/hooks/use-mobile.tsx.content:
import * as React from "react"

const MOBILE_BREAKPOINT = 768

export function useIsMobile() {
  const [isMobile, setIsMobile] = React.useState<boolean | undefined>(undefined)

  React.useEffect(() => {
    const mql = window.matchMedia(`(max-width: ${MOBILE_BREAKPOINT - 1}px)`)
    const onChange = () => {
      setIsMobile(window.innerWidth < MOBILE_BREAKPOINT)
    }
    mql.addEventListener("change", onChange)
    setIsMobile(window.innerWidth < MOBILE_BREAKPOINT)
    return () => mql.removeEventListener("change", onChange)
  }, [])

  return !!isMobile
}

