import { Send, Bot, User, Home, Sun, AlertTriangle, CheckCircle, Settings, Lightbulb, HelpCircle, CloudSun, Mic, MicOff, Menu, Search, MessageCircle, X, Square, ChevronDown, Copy, Check, LogOut } from 'lucide-react';
